from flask import Flask
from prometheus_client import Counter, Gauge, Histogram, make_metric_func, generate_latest
from prometheus_client import CONTENT_TYPE_LATEST

app = Flask(__name__)

# Define metrics
REQUEST_COUNT = Counter('requests_total', 'Total number of requests')
REQUEST_LATENCY = Histogram('request_latency_seconds', 'Request latency in seconds')
BUSINESS_METRIC = Gauge('business_metric', 'Business metric value')

def instrumented_app(func):
    @make_metric_func(REQUEST_COUNT)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.route('/')
@instrumented_app
def index():
    BUSINESS_METRIC.set(42)  # Example business metric value
    REQUEST_LATENCY.observe(0.5)  # Example request latency
    REQUEST_COUNT.inc()  # Increment request counter
    return 'Hello, World!'

if __name__ == '__main__':
    app.run(debug=True)